export function getLessonsByLevel(level) {
  return lessons.filter(l => l.level === level);
}

export function getLessonById(id) {
  return lessons.find(l => l.id === id);
}

export function isLevelUnlocked(level, completedLessons) {
  if (level === 'beginner') return true;
  if (level === 'intermediate') {
    const total = lessons.filter(l => l.level === 'beginner').length;
    const done = lessons.filter(l => l.level === 'beginner' && completedLessons.includes(l.id)).length;
    return done >= Math.ceil(total / 2);
  }
  if (level === 'advanced') {
    const total = lessons.filter(l => l.level === 'intermediate').length;
    const done = lessons.filter(l => l.level === 'intermediate' && completedLessons.includes(l.id)).length;
    return done >= Math.ceil(total / 2);
  }
  return false;
}

